// FunciГіn para limpiar texto
function limpiarTexto(texto) {
  return texto
    .replace(/(\\r\\n|\\r|\\n|\\\\n)/g, ' ')
    .replace(/\s{2,}/g, ' ')
    .replace(/\*\*/g, '')
    .trim();
}

// в”Ђв”Ђв”Ђ DETECTAR TIPO DE MENSAJE в”Ђв”Ђв”Ђ
// ACTUALIZADO: Detectar ambos formatos - markdown (**) y corchetes ([])
const tieneFormatoMarkdown = inputText.includes('**') || /\d+\)\s*\*\*/.test(inputText);
const tieneFormatoCorchetes = /\n\[.+\]\n/.test(inputText) || /^\[.+\]\n/m.test(inputText);
const tieneFormatoDePropiedad = tieneFormatoMarkdown || tieneFormatoCorchetes;

const tieneLink = inputText.includes('http') || inputText.includes('ficha.info');

console.log('Tiene formato markdown:', tieneFormatoMarkdown);
console.log('Tiene formato corchetes:', tieneFormatoCorchetes);
console.log('Tiene links:', tieneLink);

// в”Ђв”Ђв”Ђ SI ES MENSAJE SIMPLE (sin formato) в”Ђв”Ђв”Ђ
if (!tieneFormatoDePropiedad && inputText.length < 500) {
  console.log('Mensaje simple detectado');
  console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

  return [{
