    }
  }];
}

// в”Ђв”Ђв”Ђ DETECTAR SI HAY LINK DE LISTADO в”Ђв”Ђв”Ђ
const listingLinkMatch = inputText.match(/(https?:\/\/propiedades\.selfhouse\.online\/propiedades\/[^\s\)]+)/i);

if (listingLinkMatch) {
  const listingUrl = listingLinkMatch[1];
  let mensaje = inputText.replace(listingUrl, '').trim();
  mensaje = limpiarTexto(mensaje);

  if (!mensaje) mensaje = 'рџЏ  AquГ­ tienes tu selecciГіn personalizada de propiedades';

  console.log('Link de listado detectado');
  console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

  return [{
