// PROCESAR MENSAJE CON PROPIEDADES
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

console.log('Procesando mensaje con formato de propiedades...');

const resultado = [];

// в”Ђв”Ђв”Ђ SEPARAR PREGUNTA FINAL в”Ђв”Ђв”Ђ
const preguntasFinales = [
  /ВїTe interesa alguna[^?]*\?[^?]*\?/i,
  /ВїTe interesa alguna[^?]*\?/i,
  /ВїQuerГ©s que busque[^?]*\?/i,
  /ВїTe gustarГ­a[^?]*\?/i,
  /ВїNecesitГЎs[^?]*\?/i
];

let preguntaFinal = '';
let contenidoSinPregunta = inputText;

for (const regex of preguntasFinales) {
  const match = inputText.match(regex);
  if (match) {
    preguntaFinal = match[0].trim();
    contenidoSinPregunta = inputText.replace(regex, '').trim();
    console.log('Pregunta final encontrada');
    break;
  }
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// DETECTAR Y PROCESAR SEGГљN FORMATO
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

if (tieneFormatoCorchetes && !tieneFormatoMarkdown) {
  // в”Ђв”Ђв”Ђ NUEVO FORMATO: [TГ­tulo] + Precio + рџ”— в”Ђв”Ђв”Ђ
  console.log('Procesando formato con corchetes...');

  // Buscar cabecera (texto antes del primer [TГ­tulo])
  const primeraPropiedad = contenidoSinPregunta.search(/\n\[.+\]/);

  if (primeraPropiedad > 0) {
    const cabecera = contenidoSinPregunta.substring(0, primeraPropiedad).trim();
    if (cabecera) {
      resultado.push({
        json: {
          tipo: 'cabecera',
          mensaje: limpiarTexto(cabecera)
        }
      });
      console.log('Cabecera agregada:', cabecera.substring(0, 50));
    }
  }

  // Dividir por propiedades - cada una empieza con [TГ­tulo]
  // Capturar bloques completos entre cada [TГ­tulo]
  const bloques = contenidoSinPregunta.split(/(?=\n?\[(?!Ver)[^\]]+\]\n)/);

  let index = 0;

  bloques.forEach(bloque => {
    // Verificar que es un bloque de propiedad
    const tituloMatch = bloque.match(/^\n?\[([^\]]+)\]\n/);
    if (!tituloMatch) return;

    index++;
    const titulo = tituloMatch[1].trim();

    // Extraer precio
    const precioMatch = bloque.match(/Precio:\s*([^\n]+)/i);
    const precio = precioMatch ? precioMatch[1].trim() : 'Consultar';

    // Extraer ubicaciГіn
    const ubicacionMatch = bloque.match(/рџ“Ќ\s*([^\n]+)/);
    const ubicacion = ubicacionMatch ? ubicacionMatch[1].trim() : '';

    // Extraer imagen (puede venir como рџ–јпёЏ URL o ![](URL))
    let imagen = '';
    const imagenMatch = bloque.match(/рџ–јпёЏ\s*(https?:\/\/[^\s\n]+)/i) ||
                        bloque.match(/!\[.*?\]\((https?:\/\/[^\)]+)\)/) ||
                        bloque.match(/imagen:\s*(https?:\/\/[^\s\n]+)/i);
    if (imagenMatch) {
      imagen = imagenMatch[1].trim();
    }

    // Extraer ficha
    let ficha = '';
    const fichaMatch = bloque.match(/рџ”—[^\n]*:\s*(https?:\/\/[^\s\n]+)/i) ||
                       bloque.match(/\[Ver ficha[^\]]*\]\((https?:\/\/[^\)]+)\)/i) ||
                       bloque.match(/(https?:\/\/ficha\.info\/[^\s\n\)]+)/i);
    if (fichaMatch) {
      ficha = fichaMatch[1].trim();
    }

    console.log(`Propiedad ${index}:`, {
      titulo: titulo.substring(0, 30),
      precio,
      ubicacion,
      imagen: imagen ? 'SГ­' : 'No',
      ficha: ficha ? 'SГ­' : 'No'
    });

    const mensajeObj = {
      tipo: 'propiedad',
      mensaje: limpiarTexto(`${titulo} - рџ”Ґ Precio: ${precio}`),
      propiedad_index: index,
      titulo: titulo,
      precio: precio,
      ubicacion: ubicacion,
      ficha: ficha,
      message_attachments: []
    };

    // Agregar imagen si existe
    if (imagen) {
      mensajeObj.message_attachments.push({ 
        type: 'image', 
        url: imagen 
      });
    }

    // Agregar link de ficha
    if (ficha) {
      mensajeObj.message_attachments.push({ 
        type: 'link', 
        url: ficha, 
        title: 'Ver ficha completa' 
      });
    }

    resultado.push({ json: mensajeObj });
  });

  console.log('Propiedades encontradas (formato corchetes):', index);

} else {
  // в”Ђв”Ђв”Ђ FORMATO ORIGINAL: 1) **TГ­tulo** в”Ђв”Ђв”Ђ
  console.log('Procesando formato markdown...');

  // Buscar cabecera
  const primeraPropiedad = contenidoSinPregunta.search(/\d+\)\s*\*\*/);

  if (primeraPropiedad > 0) {
    const cabecera = contenidoSinPregunta.substring(0, primeraPropiedad).trim();
    if (cabecera) {
      resultado.push({
        json: {
          tipo: 'cabecera',
          mensaje: limpiarTexto(cabecera)
        }
      });
      console.log('Cabecera agregada');
    }
    contenidoSinPregunta = contenidoSinPregunta.substring(primeraPropiedad).trim();
  }

  // Dividir propiedades
  const propiedadRegex = /(\d+\)\s*\*\*[^*]+\*\*.*?)(?=\d+\)\s*\*\*|$)/gs;
  const matches = contenidoSinPregunta.match(propiedadRegex);

  console.log('Propiedades encontradas:', matches ? matches.length : 0);

  if (matches && matches.length > 0) {
    matches.forEach((propiedad, index) => {
      // Extraer tГ­tulo
      const tituloMatch = propiedad.match(/\d+\)\s*\*\*([^*]+)\*\*/);
      const titulo = tituloMatch ? tituloMatch[1].trim() : `Propiedad ${index + 1}`;

      // Extraer precio
      let precio = 'Consultar';
      const lineaPrecio = propiedad.match(/Precio[:\s]*([^\n]+)/i);

      if (lineaPrecio) {
        const textoPrecio = lineaPrecio[1].trim();
        let match = textoPrecio.match(/(USD|ARS)\s*([\d.,]+)/i);
        if (match) {
          precio = `${match[1].toUpperCase()} ${match[2]}`;
        }
        else if (match = textoPrecio.match(/\$\s*([\d.,]+)/)) {
          precio = `USD ${match[1]}`;
        }
        else if (match = textoPrecio.match(/([\d.,]+)\s*(USD|ARS|dГіlares|pesos)/i)) {
          const moneda = match[2].toLowerCase().includes('peso') ? 'ARS' : 'USD';
          precio = `${moneda} ${match[1]}`;
        }
        else if (/consultar|a convenir/i.test(textoPrecio)) {
          precio = 'Consultar';
        }
        else if (/\d/.test(textoPrecio)) {
          precio = textoPrecio;
        }
      }

      // Extraer imagen
      const imagenMatch = propiedad.match(/!\[.*?\]\(([^)]+)\)/);
      const imagen = imagenMatch ? imagenMatch[1] : '';

      // Extraer ficha
      let ficha = '';
      let fichaMatch = propiedad.match(/\[Ver ficha[^\]]*\]\(([^)]+)\)/i);
      if (!fichaMatch) {
        fichaMatch = propiedad.match(/(https?:\/\/ficha\.info\/[^\s\)]+)/i);
      }
      if (!fichaMatch) {
        fichaMatch = propiedad.match(/Ver ficha[^:]*:\s*(https?:\/\/[^\s]+)/i);
      }
      if (fichaMatch) {
        ficha = fichaMatch[1];
      }

      // Extraer ubicaciГіn
      const ubicacionMatch = propiedad.match(/рџ“Ќ\s*([^\n]+)/);
      const ubicacion = ubicacionMatch ? ubicacionMatch[1].trim() : '';

      console.log(`Propiedad ${index + 1}:`, {
        titulo: titulo.substring(0, 30),
        precio,
        imagen: imagen ? 'SГ­' : 'No',
        ficha: ficha ? 'SГ­' : 'No'
      });

      const mensajeObj = {
        tipo: 'propiedad',
        mensaje: limpiarTexto(`${titulo} - рџ”Ґ Precio: ${precio}`),
        propiedad_index: index + 1,
        titulo: titulo,
        precio: precio,
        ubicacion: ubicacion,
        ficha: ficha,
        message_attachments: []
      };

      if (imagen) {
        mensajeObj.message_attachments.push({ 
          type: 'image', 
          url: imagen 
        });
      }

      if (ficha) {
        mensajeObj.message_attachments.push({ 
          type: 'link', 
          url: ficha, 
          title: 'Ver ficha completa' 
        });
      }

      resultado.push({ json: mensajeObj });
    });
  }
}

// в”Ђв”Ђв”Ђ AGREGAR PREGUNTA FINAL в”Ђв”Ђв”Ђ
if (preguntaFinal) {
