  console.log('Pregunta final agregada');
}

// в”Ђв”Ђв”Ђ SI NO HAY NADA, RETORNAR TODO COMO CABECERA в”Ђв”Ђв”Ђ
if (resultado.length === 0) {
  console.log('No se encontrГі formato, retornando todo como cabecera');
  resultado.push({
    json: {
      tipo: 'cabecera',
      mensaje: limpiarTexto(inputText)
    }
  });
}

console.log('Total mensajes generados:', resultado.length);
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

return resultado;

