if (urlMatch) {
  propiedad.ficha_url = urlMatch[1];

  if (urlMatch[1].includes('zonaprop')) propiedad.portal = 'Zonaprop';
  else if (urlMatch[1].includes('argenprop')) propiedad.portal = 'Argenprop';
  else if (urlMatch[1].includes('mercadolibre')) propiedad.portal = 'MercadoLibre';
  else if (urlMatch[1].includes('tokko')) propiedad.portal = 'Tokko';
