  else propiedad.portal = 'Otro';
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 2. EXTRACCIГ“N DE DATOS BГЃSICOS
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

// TГ­tulo (eliminar marcas de portales)
const tituloMatch = html.match(/<title>([^<]+)<\/title>/i);
if (tituloMatch) {
  propiedad.titulo = tituloMatch[1]
    .replace(/\s*-\s*(Zonaprop|Argenprop|MercadoLibre|Properati).*$/i, "")
    .trim();
}

// DescripciГіn
const descripcionPatterns = [
  /<meta name=["']description["'] content=["']([^"']{20,}?)["']/i,
  /<meta property=["']og:description["'] content=["']([^"']{20,}?)["']/i
];
for (const pattern of descripcionPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.descripcion = match[1].substring(0, 500).trim();
    break;
  }
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 3. UBICACIГ“N (con mejor detecciГіn de barrios CABA)
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const barriosCaba = [
  'Palermo Chico', 'Palermo Hollywood', 'Palermo Soho', 'Palermo Viejo', 'Palermo',
  'Recoleta', 'Belgrano Chico', 'Belgrano C', 'Belgrano R', 'Belgrano',
  'Puerto Madero', 'Retiro', 'San Telmo', 'La Boca', 'Barracas',
  'Caballito', 'Villa Crespo', 'Colegiales', 'NГєГ±ez', 'NuГ±ez',
  'Saavedra', 'Villa Urquiza', 'Villa Devoto', 'Villa del Parque',
  'Almagro', 'Boedo', 'Flores', 'Floresta', 'Paternal',
  'Monserrat', 'ConstituciГіn', 'Villa Lugano', 'Liniers'
];

// Buscar barrio en el HTML
for (const barrio of barriosCaba) {
  const regex = new RegExp(barrio, 'i');
  if (regex.test(html)) {
    propiedad.barrio = barrio;
    propiedad.zona = 'CABA';
    break;
  }
}

// Localidad/Provincia (si no es CABA)
if (!propiedad.barrio) {
  const localidadMatch = html.match(/localidad["']?\s*[:=]\s*["']([^"']+)["']/i);
  if (localidadMatch) propiedad.localidad = localidadMatch[1];

  const provinciaMatch = html.match(/provincia["']?\s*[:=]\s*["']([^"']+)["']/i);
  if (provinciaMatch) propiedad.provincia = provinciaMatch[1];
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 4. TIPO DE PROPIEDAD Y OPERACIГ“N
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const tipos = {
  'departamento': /departamento|depto|dto/i,
  'casa': /casa\b|house/i,
  'ph': /\bph\b|p\.h\.|propiedad horizontal/i,
  'oficina': /oficina|office/i,
  'local': /local comercial|local\b/i,
  'terreno': /terreno|lote/i,
  'cochera': /cochera|garage/i
};

for (const [tipo, regex] of Object.entries(tipos)) {
  if (regex.test(html)) {
    propiedad.tipo_propiedad = tipo;
    break;
  }
}

// OperaciГіn
if (/venta|compra|en venta/i.test(html)) {
  propiedad.operacion = 'venta';
} else if (/alquiler|renta|arriendo/i.test(html)) {
  propiedad.operacion = 'alquiler';
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 5. PRECIO (con normalizaciГіn de moneda)
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const precioPatterns = [
  /"formattedAmount"\s*:\s*"([\d\.]+)"/i,
  /["']price["']\s*:\s*["'](USD|ARS)\s*([\d\.]+)/i,
  /(USD|ARS|U\$S|\$)\s*([\d\.]+)/i,
  /precio["']?\s*[:=]\s*["']?([\d\.]+)/i
];

for (const pattern of precioPatterns) {
  const match = html.match(pattern);
  if (match) {
    // Detectar moneda
    const monedaMatch = match[0].match(/USD|ARS|U\$S|\$/i);
    if (monedaMatch) {
      const m = monedaMatch[0].toUpperCase();
      propiedad.moneda = (m === 'U$S' || m === '$') ? 'USD' : m;
    } else {
      propiedad.moneda = 'USD'; // default
    }

    // Extraer nГєmero sin puntos
    const numero = match[match.length - 1].replace(/\./g, "");
    propiedad.precio = numero;
    break;
  }
}

if (!propiedad.precio) propiedad.precio = "Consultar";

// Expensas
const expensasMatch = html.match(/expensas?\s*[:=]?\s*([\d\.]+)/i);
if (expensasMatch) {
  propiedad.expensas = expensasMatch[1].replace(/\./g, "");
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 6. CARACTERГЌSTICAS (ambientes, dormitorios, baГ±os)
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

// Ambientes
const ambientesPatterns = [
  /(\d+)\s*ambientes?/i,
  /["']ambientes?["']\s*[:=]\s*(\d+)/i
];
for (const pattern of ambientesPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.ambientes = parseInt(match[1], 10);
    break;
  }
}

// Dormitorios
const dormitoriosPatterns = [
  /(\d+)\s*(?:dormitorios?|habitaciones?|cuartos?)/i,
  /["']bedrooms?["']\s*[:=]\s*(\d+)/i
];
for (const pattern of dormitoriosPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.dormitorios = parseInt(match[1], 10);
    break;
  }
}

// BaГ±os
const banosPatterns = [
  /(\d+)\s*baГ±os?/i,
  /(\d+)\s*banos?/i,
  /["']bathrooms?["']\s*[:=]\s*(\d+)/i
];
for (const pattern of banosPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.banos = parseInt(match[1], 10);
    break;
  }
}

// Cocheras
const cocherasMatch = html.match(/(\d+)\s*cocheras?/i);
if (cocherasMatch) {
  propiedad.cocheras = parseInt(cocherasMatch[1], 10);
}

// Superficie
const supPatterns = [
  /(\d+)\s*m[ВІ2]\s*(?:totales?|total)?/i,
  /superficie\s*total[:\s]*(\d+)/i
];
for (const pattern of supPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.superficie_total = parseInt(match[1], 10);
    break;
  }
}

const supCubMatch = html.match(/(\d+)\s*m[ВІ2]\s*cubiertos?/i);
if (supCubMatch) {
  propiedad.superficie_cubierta = parseInt(supCubMatch[1], 10);
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 7. AMENITIES
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const amenitiesList = [
  'pileta', 'piscina', 'gimnasio', 'sum', 'quincho', 'parrilla',
  'terraza', 'balcГіn', 'balcon', 'jardГ­n', 'jardin', 'cochera',
  'baulera', 'seguridad', 'portero', 'aire acondicionado',
  'calefacciГіn', 'calefaccion', 'laundry', 'lavadero'
];

amenitiesList.forEach(amenity => {
  const regex = new RegExp(amenity, 'i');
  if (regex.test(html)) {
    propiedad.amenities.push(amenity);
  }
});

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 8. AGENTE INMOBILIARIO
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const inmobiliariaMatch = html.match(/inmobiliaria["']?\s*[:=]\s*["']?([^"'<>\n]{3,50})/i);
if (inmobiliariaMatch) {
  propiedad.inmobiliaria = inmobiliariaMatch[1].trim();
}

// TelГ©fono
const telefonoMatch = html.match(/(?:tel[eГ©]fono|phone|contacto)["']?\s*[:=]?\s*["']?([\d\s\-\+\(\)]{8,20})/i);
if (telefonoMatch) {
  propiedad.telefono = telefonoMatch[1].replace(/\s/g, '');
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 9. IDs Y METADATA
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

// postingCode (ID de Zonaprop/Navent)
const postingPatterns = [
  /["']postingCode["']\s*:\s*["']([A-Z0-9\-]+)["']/i,
  /postingCode["']?\s*[:=]\s*["']([A-Z0-9\-]+)["']/i,
  /id[-_]?aviso["']?\s*[:=]\s*["']?(\d+)/i
];
for (const pattern of postingPatterns) {
  const match = html.match(pattern);
  if (match) {
    propiedad.propiedad_id = match[1];
    break;
  }
}

// AntigГјedad
const antiguedadMatch = html.match(/(\d+)\s*aГ±os?\s*(?:de\s*)?antig[uГј]edad/i);
if (antiguedadMatch) {
  propiedad.antiguedad = `${antiguedadMatch[1]} aГ±os`;
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 10. FOTOS (sin duplicados, mГЎximo 10)
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

const fotosSet = new Set();

// og:image
const ogImage = html.match(/<meta property=["']og:image["'] content=["']([^"']+)["']/i);
if (ogImage) fotosSet.add(ogImage[1]);

// CDN de portales argentinos
const cdnPatterns = [
  /https?:\/\/imgar\.zonapropcdn\.com\/[^\s"'<>)]+/ig,
  /https?:\/\/static\.tokkobroker\.com\/[^\s"'<>)]+/ig,
  /https?:\/\/http2\.mlstatic\.com\/[^\s"'<>)]+/ig,
  /https?:\/\/[^\s"'<>)]*\.properati\.com[^\s"'<>)]+/ig
];

cdnPatterns.forEach(pattern => {
  const matches = html.match(pattern) || [];
  matches.forEach(url => fotosSet.add(url));
});

propiedad.fotos = Array.from(fotosSet).slice(0, 10);

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// 11. NORMALIZACIГ“N Y DEFAULTS
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

// TГ­tulo: si estГЎ vacГ­o, generar uno descriptivo
if (!propiedad.titulo) {
  propiedad.titulo = [
    propiedad.tipo_propiedad,
    propiedad.ambientes ? `${propiedad.ambientes} amb` : '',
    propiedad.barrio || propiedad.localidad,
    propiedad.operacion
  ].filter(Boolean).join(' ');
}

// Moneda default
if (!propiedad.moneda && propiedad.precio !== "Consultar") {
  propiedad.moneda = 'USD';
}

// Asesor default (Juejati)
if (!propiedad.asesor) {
  propiedad.asesor = "Equipo Juejati";
}

